import{_ as e}from"./chunks/quick_control_icon.Cc9UwUrp.js";import{_ as i,c,o as d,aj as a}from"./chunks/framework.CjkNaYQl.js";const P=JSON.parse('{"title":"6. 自主練習","description":"","frontmatter":{},"headers":[],"relativePath":"basic/6.md","filePath":"basic/6.md"}'),t={name:"basic/6.md"};function l(s,o,n,r,m,_){return d(),c("div",null,[...o[0]||(o[0]=[a('<h1 id="_6-自主練習" tabindex="-1">6. 自主練習 <a class="header-anchor" href="#_6-自主練習" aria-label="Permalink to &quot;6. 自主練習&quot;">​</a></h1><h2 id="題目" tabindex="-1">題目 <a class="header-anchor" href="#題目" aria-label="Permalink to &quot;題目&quot;">​</a></h2><p>請辨識並夾起麻將塊，並把麻將塊夾起到放置麻將塊的小板子內，板子上會放置 Landmark，麻將和放置麻將塊的小板子位置不固定。在流程結尾須有 <code>Stop</code> 節點。</p><h2 id="驗證" tabindex="-1">驗證 <a class="header-anchor" href="#驗證" aria-label="Permalink to &quot;驗證&quot;">​</a></h2><ol><li>麻將塊放置位置不固定，看手臂是否有辦法精準夾到麻將（建議麻將放置不要旋轉超過 180°）</li><li>麻將放置板放置位置不固定，看手臂是否有辦法精準將麻將放到板中凹槽（建議板子放置不要超過 180°）</li><li>流程結束後，是否自動退出專案執行畫面</li></ol><h2 id="答案" tabindex="-1">答案 <a class="header-anchor" href="#答案" aria-label="Permalink to &quot;答案&quot;">​</a></h2><ol><li><code>Point</code>（Robot Base）：可以在初始位置先打一個 <code>Point</code>，要足夠高，以免移動到視覺任務的點位時撞機</li><li><code>Vision</code>（Positioning，Robot Base）：移動到放置麻將的區塊後，設定 <code>物件定位</code> 的視覺任務，辨識麻將上的 <strong>TM</strong> Logo（此步完成後，會自動建立 Vision Base）</li><li><code>Point</code>（Vision Base）：將手臂向下拉到麻將上，且手臂可以夾起麻將的位置（麻將位置不能移動到），可利用畫面上方 <img src="'+e+'" alt="Quick Control 圖標" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;">，並用控制器 <code>+</code> 和 <code>-</code> 來細微控制坐標</li><li><code>Set</code>：末端模組的 <code>DO_0</code> 設為 <code>H</code>，並按下 <code>輸出測試</code> 以夾起麻將</li><li><code>Wait for</code>：等待 <code>500 ms</code>，確保麻將能被夾起</li><li><code>Move</code>：<code>Z</code> 設為 <code>-100 mm</code>，確保手臂不會撞機，此步也可用另一個垂直向上的 <code>Point</code> 代替</li><li><code>Point</code>（Robot Base）：移動到較高的位置，為放置麻將塊的小板子的視覺任務做準備</li><li><code>Vision</code>（Positioning，Robot Base）：移動到放置麻將的小板子上方，設定 <code>TM Landmark</code> 的視覺任務，辨識板子上的 Landmark（此步完成後，會自動建立 Vision Base）</li><li><code>Point</code>（Vision Base）：將手臂移動到板子上，並將已夾起的麻將對好板子的某一格凹槽（麻將位置不能移動到），可利用畫面上方 <img src="'+e+'" alt="Quick Control 圖標" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;">，並用控制器 <code>+</code> 和 <code>-</code> 來細微控制坐標</li><li><code>Set</code>：末端模組的 <code>DO_0</code> 設為 <code>L</code>，並按下 <code>輸出測試</code> 以放下麻將</li><li><code>Wait for</code>：等待 <code>500 ms</code>，確保麻將能被放下</li><li><code>Move</code>：<code>Z</code> 設為 <code>-100 mm</code>，確保手臂不會撞機，此步也可用另一個垂直向上的 <code>Point</code> 代替</li><li><code>Point</code>（Robot Base）：可以在結束位置打一個 <code>Point</code></li><li><code>Stop</code></li></ol><div class="info custom-block"><p class="custom-block-title">小技巧</p><p>可將所有 <code>Vision</code> 的 <code>Miss</code>，都用一個 <code>Goto</code> 節點連結，並連回該 <code>Vision</code>。</p></div>',8)])])}const b=i(t,[["render",l]]);export{P as __pageData,b as default};
